class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(255), unique=True, nullable=False, index=True)
    password_hash = db.Column(db.String(255), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(32), nullable=True)
    mfa_verified = db.Column(db.Boolean, default=False)  # True only after first successful TOTP verification
    mfa_backup_codes_hash = db.Column(db.Text, nullable=True)  # JSON list of hashed backup codes
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    updated_at = db.Column(db.DateTime, default=datetime.utcnow, onupdate=datetime.utcnow)

    # MFA reset tracking
    last_mfa_reset_request = db.Column(db.DateTime, nullable=True)
    mfa_reset_count_hour = db.Column(db.Integer, default=0)
    mfa_reset_count_hour_start = db.Column(db.DateTime, nullable=True)

    # Login attempt tracking
    failed_login_attempts = db.Column(db.Integer, default=0)
    last_failed_login = db.Column(db.DateTime, nullable=True)
    account_locked_until = db.Column(db.DateTime, nullable=True)

    # Pending MFA reset state
    mfa_reset_pending = db.Column(db.Boolean, default=False)
    mfa_reset_token_hash = db.Column(db.String(128), nullable=True)
    mfa_reset_token_created = db.Column(db.DateTime, nullable=True)
    mfa_reset_completed_at = db.Column(db.DateTime, nullable=True)

    # Re-authentication requirement after MFA reset
    require_password_change = db.Column(db.Boolean, default=False)

    def set_password(self, password):
        self.password_hash = generate_password_hash(password, method='pbkdf2:sha256:600000')

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    def generate_mfa_secret(self):
        self.mfa_secret = pyotp.random_base32()
        self.mfa_verified = False
        return self.mfa_secret

    def get_totp(self):
        if self.mfa_secret:
            return pyotp.TOTP(self.mfa_secret)
        return None

    def verify_totp(self, token):
        totp = self.get_totp()
        if totp:
            # valid_window=1 allows for slight time drift (30 seconds each way)
            return totp.verify(token, valid_window=1)
        return False

    def generate_backup_codes(self):
        import json
        codes = [secrets.token_hex(4).upper() for _ in range(10)]
        hashed_codes = [hashlib.sha256(code.encode()).hexdigest() for code in codes]
        self.mfa_backup_codes_hash = json.dumps(hashed_codes)
        return codes

    def verify_backup_code(self, code):
        import json
        if not self.mfa_backup_codes_hash:
            return False
        hashed_codes = json.loads(self.mfa_backup_codes_hash)
        code_hash = hashlib.sha256(code.strip().upper().encode()).hexdigest()
        if code_hash in hashed_codes:
            hashed_codes.remove(code_hash)
            self.mfa_backup_codes_hash = json.dumps(hashed_codes)
            db.session.commit()
            return True
        return False

    def is_account_locked(self):
        if self.account_locked_until and self.account_locked_until > datetime.utcnow():
            return True
        if self.account_locked_until and self.account_locked_until <= datetime.utcnow():
            self.account_locked_until = None
            self.failed_login_attempts = 0
            db.session.commit()
        return False

    def record_failed_login(self):
        now = datetime.utcnow()
        self.failed_login_attempts += 1
        self.last_failed_login = now
        if self.failed_login_attempts >= LOGIN_MAX_ATTEMPTS:
            lockout_minutes = min(2 ** (self.failed_login_attempts - LOGIN_MAX_ATTEMPTS) * 5, 60)
            self.account_locked_until = now + timedelta(minutes=lockout_minutes)
        db.session.commit()

    def record_successful_login(self):
        self.failed_login_attempts = 0
        self.last_failed_login = None
        self.account_locked_until = None
        db.session.commit()

    def can_request_mfa_reset(self):
        now = datetime.utcnow()
        # Rate limit: one request per MFA_RESET_RATE_LIMIT_SECONDS
        if self.last_mfa_reset_request:
            elapsed = (now - self.last_mfa_reset_request).total_seconds()
            if elapsed < MFA_RESET_RATE_LIMIT_SECONDS:
                return False, f"Please wait {int(MFA_RESET_RATE_LIMIT_SECONDS - elapsed)} seconds before requesting another reset."

        # Hourly limit
        if self.mfa_reset_count_hour_start:
            if (now - self.mfa_reset_count_hour_start).total_seconds() > 3600:
                self.mfa_reset_count_hour = 0
                self.mfa_reset_count_hour_start = now
        else:
            self.mfa_reset_count_hour_start = now

        if self.mfa_reset_count_hour >= MFA_RESET_MAX_ATTEMPTS:
            return False, "Maximum MFA reset attempts reached. Please try again later or contact support."

        return True, "OK"


