@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    password = data.get('password', '')

    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400

    if len(password) < 12:
        return jsonify({'error': 'Password must be at least 12 characters'}), 400

    if User.query.filter_by(email=email).first():
        # Don't reveal whether email exists - use generic message
        # But still return success to prevent enumeration
        # In production, you'd want to send an email saying "someone tried to register with your email"
        return jsonify({'message': 'If this email is not already registered, an account has been created. Please check your email.'}), 200

    user = User(email=email)
    user.set_password(password)
    db.session.add(user)
    db.session.commit()

    log_audit(user.id, 'register', 'Account created')

    return jsonify({'message': 'If this email is not already registered, an account has been created. Please check your email.'}), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    password = data.get('password', '')

    if not email or not password:
        return jsonify({'error': 'Email and password are required'}), 400

    user = User.query.filter_by(email=email).first()

    # Use constant-time comparison approach - always check password even if user doesn't exist
    if not user:
        # Perform a dummy password check to prevent timing attacks
        generate_password_hash('dummy_password_to_waste_time', method='pbkdf2:sha256:600000')
        return jsonify({'error': 'Invalid email or password'}), 401

    if user.is_account_locked():
        log_audit(user.id, 'login_blocked', 'Account locked due to too many failed attempts')
        return jsonify({'error': 'Account is temporarily locked due to too many failed attempts. Please try again later.'}), 429

    if not user.check_password(password):
        user.record_failed_login()
        log_audit(user.id, 'login_failed', 'Invalid password')
        return jsonify({'error': 'Invalid email or password'}), 401

    # Password is correct
    if user.mfa_enabled and user.mfa_verified:
        # MFA is enabled - require second factor
        session['user_id'] = user.id
        session['mfa_pending'] = True
        session['mfa_login_time'] = time.time()
        log_audit(user.id, 'login_password_ok', 'Password verified, MFA pending')
        return jsonify({
            'message': 'Password verified. Please provide your MFA code.',
            'mfa_required': True
        }), 200
    else:
        # No MFA - complete login
        session['user_id'] = user.id
        session['mfa_pending'] = False
        session['login_time'] = time.time()
        user.record_successful_login()
        log_audit(user.id, 'login_success', 'Login without MFA')

        response_data = {
            'message': 'Login successful',
            'mfa_enabled': user.mfa_enabled
        }

        # If MFA was recently reset, warn the user
        if user.mfa_reset_completed_at:
            reset_age = (datetime.utcnow() - user.mfa_reset_completed_at).total_seconds()
            if reset_age < 86400:  # Within 24 hours
                response_data['warning'] = 'MFA was recently disabled on your account. We strongly recommend re-enabling it.'

        return jsonify(response_data), 200


@app.route('/login/mfa', methods=['POST'])
def login_mfa():
    if 'user_id' not in session or not session.get('mfa_pending'):
        return jsonify({'error': 'No pending MFA verification'}), 400

    # Check MFA session timeout (5 minutes)
    mfa_login_time = session.get('mfa_login_time', 0)
    if time.time() - mfa_login_time > 300:
        session.clear()
        return jsonify({'error': 'MFA verification timed out. Please log in again.'}), 401

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    user = User.query.get(session['user_id'])
    if not user:
        session.clear()
        return jsonify({'error': 'User not found'}), 401

    mfa_code = data.get('mfa_code', '').strip()
    backup_code = data.get('backup_code', '').strip()

    verified = False

    if mfa_code:
        if not mfa_code.isdigit() or len(mfa_code) != 6:
            user.record_failed_login()
            log_audit(user.id, 'mfa_failed', 'Invalid MFA code format')
            return jsonify({'error': 'Invalid MFA code format'}), 401

        if user.verify_totp(mfa_code):
            verified = True
        else:
            user.record_failed_login()
            log_audit(user.id, 'mfa_failed', 'Invalid TOTP code')
            return jsonify({'error': 'Invalid MFA code'}), 401

    elif backup_code:
        if user.verify_backup_code(backup_code):
            verified = True
            log_audit(user.id, 'backup_code_used', 'Backup code used for login')
        else:
            user.record_failed_login()
            log_audit(user.id, 'mfa_failed', 'Invalid backup code')
            return jsonify({'error': 'Invalid backup code'}), 401
    else:
        return jsonify({'error': 'MFA code or backup code required'}), 400

    if verified:
        session['mfa_pending'] = False
        session['login_time'] = time.time()
        user.record_successful_login()
        log_audit(user.id, 'login_success', 'MFA verified')
        return jsonify({'message': 'Login successful'}), 200


@app.route('/mfa/enable', methods=['POST'])
@login_required
def enable_mfa():
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user.mfa_enabled and user.mfa_verified:
        return jsonify({'error': 'MFA is already enabled'}), 400

    # Require password re-verification for enabling MFA
    data = request.get_json() or {}
    password = data.get('password', '')
    if not password or not user.check_password(password):
        return jsonify({'error': 'Password verification required to enable MFA'}), 403

    secret = user.generate_mfa_secret()
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(name=user.email, issuer_name='MFA System')

    # Generate QR code
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    qr_base64 = base64.b64encode(buffer.getvalue()).decode()

    user.mfa_enabled = True
    user.mfa_verified = False  # Not verified until first TOTP confirmation
    db.session.commit()

    log_audit(user.id, 'mfa_setup_started', 'MFA setup initiated')

    return jsonify({
        'message': 'MFA setup initiated. Please verify with a TOTP code to complete setup.',
        'secret': secret,
        'qr_code': f'data:image/png;base64,{qr_base64}',
        'provisioning_uri': provisioning_uri
    }), 200


@app.route('/mfa/verify-setup', methods=['POST'])
@login_required
def verify_mfa_setup():
    """Verify the first TOTP code to confirm MFA setup."""
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user.mfa_enabled or user.mfa_verified:
        return jsonify({'error': 'No pending MFA setup to verify'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    mfa_code = data.get('mfa_code', '').strip()
    if not mfa_code or not mfa_code.isdigit() or len(mfa_code) != 6:
        return jsonify({'error': 'Valid 6-digit MFA code required'}), 400

    if user.verify_totp(mfa_code):
        user.mfa_verified = True
        backup_codes = user.generate_backup_codes()
        db.session.commit()

        log_audit(user.id, 'mfa_enabled', 'MFA setup completed and verified')

        return jsonify({
            'message': 'MFA has been successfully enabled!',
            'backup_codes': backup_codes,
            'warning': 'Save these backup codes in a secure location. They will not be shown again.'
        }), 200
    else:
        return jsonify({'error': 'Invalid MFA code. Please try again.'}), 400


@app.route('/mfa/disable', methods=['POST'])
@login_required
def disable_mfa():
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user.mfa_enabled:
        return jsonify({'error': 'MFA is not enabled'}), 400

    data = request.get_json() or {}

    # Require both password and current MFA code to disable
    password = data.get('password', '')
    mfa_code = data.get('mfa_code', '').strip()

    if not password or not user.check_password(password):
        return jsonify({'error': 'Password verification required'}), 403

    if user.mfa_verified:
        if not mfa_code:
            return jsonify({'error': 'Current MFA code required to disable MFA'}), 400
        if not user.verify_totp(mfa_code):
            return jsonify({'error': 'Invalid MFA code'}), 401

    user.mfa_enabled = False
    user.mfa_secret = None
    user.mfa_verified = False
    user.mfa_backup_codes_hash = None
    db.session.commit()

    log_audit(user.id, 'mfa_disabled', 'MFA disabled by user')

    return jsonify({'message': 'MFA has been disabled'}), 200


@app.route('/reset-mfa', methods=['POST'])
def request_mfa_reset():
    """
    Request an MFA reset. Sends a reset link to the user's registered email.
    This endpoint intentionally returns the same response regardless of whether
    the email exists to prevent user enumeration.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    email = data.get('email', '').strip().lower()
    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Always return the same response to prevent email enumeration
    generic_response = {
        'message': 'If an account with MFA enabled exists for this email, a reset link has been sent. Please check your inbox.'
    }

    user = User.query.filter_by(email=email).first()

    if not user:
        # Simulate processing time to prevent timing attacks
        time.sleep(0.5)
        log_audit(None, 'mfa_reset_request_unknown_email', f'Reset requested for unknown email')
        return jsonify(generic_response), 200

    if not user.mfa_enabled:
        time.sleep(0.5)
        log_audit(user.id, 'mfa_reset_request_no_mfa', 'Reset requested but MFA not enabled')
        return jsonify(generic_response), 200

    # Check rate limiting
    can_reset, rate_limit_msg = user.can_request_mfa_reset()
    if not can_reset:
        log_audit(user.id, 'mfa_reset_rate_limited', rate_limit_msg)
        # Still return generic response to prevent enumeration, but with 429 status
        return jsonify({'message': 'Too many requests. Please try again later.'}), 429

    # Generate and send reset token
    token = generate_reset_token(user)

    # Update rate limiting counters
    user.last_mfa_reset_request = datetime.utcnow()
    user.mfa_reset_count_hour += 1
    db.session.commit()

    email_sent = send_reset_email(user, token)

    if email_sent:
        log_audit(user.id, 'mfa_reset_email_sent', f'MFA reset email sent to {user.email}')
    else:
        log_audit(user.id, 'mfa_reset_email_failed', 'Failed to send MFA reset email')
        # Revert the pending state if email failed
        user.mfa_reset_pending = False
        user.mfa_reset_token_hash = None
        db.session.commit()

    return jsonify(generic_response), 200


@app.route('/reset-mfa/confirm/<token>', methods=['GET'])
def confirm_mfa_reset_page(token):
    """
    GET endpoint - shows a confirmation page (in a real app, this would render HTML).
    The actual reset happens on POST to prevent CSRF via link prefetching.
    """
    user, error = verify_reset_token(token)
    if error:
        return jsonify({'error': error}), 400

    return jsonify({
        'message': 'Please confirm MFA reset by sending a POST request to this endpoint.',
        'email': user.email,
        'action_required': 'POST to confirm'
    }), 200


@app.route('/reset-mfa/confirm/<token>', methods=['POST'])
def confirm_mfa_reset(token):
    """
    Confirm MFA reset. This actually disables MFA on the account.
    Requires POST to prevent CSRF via link prefetching/preloading.
    """
    user, error = verify_reset_token(token)
    if error:
        log_audit(None, 'mfa_reset_confirm_failed', f'Token verification failed: {error}')
        return jsonify({'error': error}), 400

    # Mark token as used (prevent replay)
    token_hash = hashlib.sha256(token.encode()).hexdigest()
    used_token = UsedToken(
        token_hash=token_hash,
        expires_at=datetime.utcnow() + timedelta(seconds=MFA_RESET_TOKEN_MAX_AGE + 3600)
    )
    db.session.add(used_token)

    # Disable MFA
    user.mfa_enabled = False
    user.mfa_secret = None
    user.mfa_verified = False
    user.mfa_backup_codes_hash = None
    user.mfa_reset_pending = False
    user.mfa_reset_token_hash = None
    user.mfa_reset_token_created = None
    user.mfa_reset_completed_at = datetime.utcnow()

    db.session.commit()

    log_audit(user.id, 'mfa_reset_completed', 'MFA disabled via email reset link')

    # Send notification that MFA was disabled
    send_mfa_disabled_notification(user)

    # Invalidate all existing sessions for this user
    # In production, you'd use a session store and invalidate all sessions
    # For this implementation, we clear the current session
    session.clear()

    return jsonify({
        'message': 'MFA has been successfully disabled. You can now log in with just your password.',
        'recommendation': 'Please re-enable MFA as soon as possible to keep your account secure.'
    }), 200


@app.route('/mfa/status', methods=['GET'])
@login_required
def mfa_status():
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    import json
    backup_codes_remaining = 0
    if user.mfa_backup_codes_hash:
        try:
            codes = json.loads(user.mfa_backup_codes_hash)
            backup_codes_remaining = len(codes)
        except (json.JSONDecodeError, TypeError):
            pass

    return jsonify({
        'mfa_enabled': user.mfa_enabled,
        'mfa_verified': user.mfa_verified,
        'backup_codes_remaining': backup_codes_remaining,
        'mfa_reset_completed_at': user.mfa_reset_completed_at.isoformat() if user.mfa_reset_completed_at else None
    }), 200


@app.route('/mfa/regenerate-backup-codes', methods=['POST'])
@login_required
def regenerate_backup_codes():
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user.mfa_enabled or not user.mfa_verified:
        return jsonify({'error': 'MFA must be enabled and verified'}), 400

    data = request.get_json() or {}

    # Require password and MFA code
    password = data.get('password', '')
    mfa_code = data.get('mfa_code', '').strip()

    if not password or not user.check_password(password):
        return jsonify({'error': 'Password verification required'}), 403

    if not mfa_code or not user.verify_totp(mfa_code):
        return jsonify({'error': 'Valid MFA code required'}), 401

    backup_codes = user.generate_backup_codes()
    db.session.commit()

    log_audit(user.id, 'backup_codes_regenerated', 'Backup codes regenerated')

    return jsonify({
        'message': 'New backup codes generated. Previous codes are now invalid.',
        'backup_codes': backup_codes,
        'warning': 'Save these backup codes in a secure location. They will not be shown again.'
    }), 200


@app.route('/logout', methods=['POST'])
def logout():
    user_id = session.get('user_id')
    session.clear()
    if user_id:
        log_audit(user_id, 'logout', 'User logged out')
    return jsonify({'message': 'Logged out successfully'}), 200


@app.route('/audit-log', methods=['GET'])
@login_required
def view_audit_log():
    user = User.query.get(session['user_id'])
    if not user:
        return jsonify({'error': 'User not found'}), 404

    logs = AuditLog.query.filter_by(user_id=user.id).order_by(
        AuditLog.timestamp.desc()
    ).limit(50).all()

    return jsonify({
        'audit_log': [
            {
                'action': log.action,
                'details': log.details,
                'ip_address': log.ip_address,
                'timestamp': log.timestamp.isoformat()
            }
            for log in logs
        ]
    }), 200


def cleanup_expired_tokens():
    """Periodic cleanup of expired used tokens."""
    expired = UsedToken.query.filter(UsedToken.expires_at < datetime.utcnow()).all()
    for token in expired:
        db.session.delete(token)
    db.session.commit()


with app.app_context():
    db.create_all()


